class Solution {
    public int minSwapsCouples(int[] row) {
        int n = row.length / 2;
        int swaps = 0;
        for (int i = 0; i < n; i++) {
            if (row[i] % 2 != i / 2) {
                swaps++;
                int target = i / 2 * 2;
                int temp = row[i];
                row[i] = row[target];
                row[target] = temp;
            }
        }
        return swaps;
    }
}
